bad_example.code:
# Bad: Complex bit manipulation without proven need
def is_even(n):
    return not (n & 1)

# Bad: Inline caching without profiling
_cache = {}
def get_user(id):
    if id not in _cache:
        _cache[id] = expensive_db_call(id)
    return _cache[id]

good_example.code:
# Good: Clear and readable
def is_even(n):
    return n % 2 == 0

# Good: Add caching AFTER profiling shows it's needed
@functools.lru_cache(maxsize=1000)
def get_user(id):
    return expensive_db_call(id)
